import React, { useEffect, useState } from 'react';
import axios from "axios";
import "./Project.css";

const API_BASE_URL = "http://51.83.75.252:5240/api";

interface Project {
    idProject: number;
    title: string;
    description: string;
    githubLink: string;
    webLink?: string;
    technoPaths: string[];
    imagePaths: string[];
}

const Projects: React.FC = () => {
    const [projects, setProjects] = useState<Project[]>([]);
    const [isLoading, setIsLoading] = useState<boolean>(true);
    const [error, setError] = useState<string | null>(null);

    const fetchProjects = async () => {
        try {
            setIsLoading(true);
            const response = await axios.get<Project[]>(`${API_BASE_URL}/project/all`);
            setProjects(response.data);
            setError(null);
        } catch (err) {
            console.error("Erreur lors de la récupération des projets", err);
            setError("Impossible de charger les projets. Veuillez réessayer.");
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchProjects();
    }, []);

    if (isLoading) return <div>Chargement des projets...</div>;
    if (error) return <div>{error}</div>;

    return (
        <div className="project-container">
            {projects.map((project) => (
                <div key={project.idProject} className="project-card">
                    <div className="project-card-title">
                        <p className="project-title">{project.title}</p>
                    </div>
                    <div className="project-technologies">
                        <p className="project-tech-label">Technos :</p>
                        {project.technoPaths.map((path, index) => (
                            <img
                                key={index}
                                src={path}
                                alt={`Technologie ${index + 1}`}
                                className="project-tech-icon"
                            />
                        ))}
                    </div>
                    <div className="project-image-container">
                        {project.imagePaths.map((path, index) => (
                            <div key={index} className="project-image-wrapper">
                                <img
                                    src={path}
                                    alt={`Projet ${project.title}, image ${index + 1}`}
                                    className="project-image"
                                />
                            </div>
                        ))}
                    </div>

                    <div className="project-links">
                        <a
                            href={project.githubLink}
                            target="_blank"
                            rel="noreferrer"
                            className="project-github-link"
                        >
                            <img
                                src="/Logo/github.svg"
                                alt="GitHub"
                                className="project-link-icon"
                            />
                            <span className="project-link-text">
                                Voir le repo sur Github
                            </span>
                        </a>

                        {project.webLink && (
                            <a
                                href={project.webLink}
                                target="_blank"
                                rel="noreferrer"
                                className="project-web-link"
                            >
                                <img
                                    src="/Logo/web.svg"
                                    alt="Web"
                                    className="project-link-icon"
                                />
                                <span className="project-link-text">
                                    Voir le site web
                                </span>
                            </a>
                        )}
                    </div>
                </div>
            ))}
        </div>
    );
};

export default Projects;
